#include<bits/stdc++.h>
using namespace std;
int fa[2000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,m;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n*2;i++)
        {
            fa[i]=i;
        }
        int flag=0;
        for(int i=1;i<=m;i++)
        {
            int a,b,c;
            scanf("%d%d%d",&a,&b,&c);
            if(a!=b&&c==0)
            {
                flag=1;
                continue;
            }
            if(a==b&&c!=0&&n==1)
            {
                flag=1;
                continue;
            }
            if(c%2==0)
            {
                merge(a,b);
                merge(a+n,b+n);
            }
            else
            {
                merge(a,b+n);
                merge(a+n,b);
            }
        }
        if(flag)
        {
            printf("No\n");
            continue;
        }
        flag=1;
        for(int i=1;i<=n;i++)
        {
            if(find(i)==find(i+n))
            {
                flag=1;
                break;
            }
            if(find(i)!=find(1))
            {
                flag=0;
            }
        }
        if(flag)
        {
            printf("No\n");
            continue;
        }
        printf("Yes\n");
    }
    return 0;
}
